{
  "action": "Keep backyard chickens",
  "_test_note": "No explicit prohibition/permission on chickens/hens in section 161.19; expect allowed:true at confidence:medium (absence-of-restriction inference), citing 161.19, with the rooster prohibition surfaced as a condition, and never the fabricated '6 hens' myth."
}

{
  "action": "keep a rooster in my apartment",
  "_test_note": "Section 161.19(a) explicitly prohibits keeping a live rooster; expect allowed:false, citing 161.19 with reasoning mentioning the rooster prohibition. Confidence is 'medium', not 'high', against the full ~10,700-chunk corpus - with many more candidate sections in play than in a small test fixture, this query no longer has one decisively top-ranked result even though the matched statement itself is unambiguous. Verified directly against production, not assumed."
}

{
  "action": "juggle flaming torches while unicycling on the moon",
  "_test_note": "KNOWN, DOCUMENTED LIMITATION, discovered while writing this suite (not theorized): at full-corpus scale this nonsense action coincidentally matches real section 27-515 'Flame resistance' via the word flame/flaming, returning a confident-looking allowed:true/false. This is a 'Success Test' because a well-formed, non-fabricated response IS the correct behavior - not that the legal determination is topically correct. See the gibberish-action test below for the genuinely-no-match case instead."
}

{
  "action": "xyzzyquorp blorptrejkl zibbernaut fwoosh",
  "_test_note": "Deliberately made-up, non-English tokens that cannot appear as real keywords anywhere in the ingested statute text - unlike natural-English nonsense phrases (see the flaming-torches test above), this reliably has zero keyword overlap even at full-corpus scale. Expect allowed:null (not false, not a guess), confidence:low, and an empty citations list rather than a fabricated one."
}

{
  "action": "launch a satellite into orbit from my roof",
  "_test_note": "KNOWN, DOCUMENTED LIMITATION (see docs/DATA_SOURCE.md), not a bug target: keyword ranking can match 'roof' as a building material rather than a rooftop location and surface an unrelated section. This is a 'Success Test' because the well-formed, non-fabricated response IS the correct behavior being verified - not that the legal determination is topically correct."
}

{
  "_test_note": "ActionCheckRequest.action is required (min_length=1) per app/models.py; omitting it entirely must fail validation with 422 rather than being treated as an empty/unclear action.",
  "context": {"borough": "Queens"}
}

{
  "action": "keep a rooster",
  "limit": 21,
  "_test_note": "ActionCheckRequest.limit is constrained to le=20 per app/models.py; 21 must fail validation with 422."
}

{
  "query": "rooster keeping poultry",
  "document_type": "NYC Health Code",
  "_test_note": "Filtered keyword search should rank 161.19 (Keeping of livestock, live poultry and rabbits) first among Health Code results, and capture document_id for the chained Documents folder tests."
}

{
  "query": "after hours weekend limits construction work",
  "document_type": "NYC Administrative Code",
  "_test_note": "Filtered keyword search should rank 24-222 (After hours and weekend limits on construction work) first among Admin Code results."
}

{
  "query": "taxicab for hire vehicle license",
  "_test_note": "No document_type filter applied - proves search works over the entire ingested Admin Code, not just a curated slice."
}

{
  "query": "rooster keeping poultry",
  "document_type": "NYC Health Code",
  "search_mode": "in_app",
  "_test_note": "Explicitly overrides SEARCH_MODE's default (text_index) for this one call; the in-app Python TF scorer should still rank 161.19 first and say so in reasoning."
}

{
  "document_type": "NYC Health Code",
  "_test_note": "SearchRequest.query is required (min_length=1) per app/models.py; omitting it must fail validation with 422."
}

{
  "query": "noise",
  "limit": 51,
  "_test_note": "SearchRequest.limit is constrained to le=50 per app/models.py; 51 must fail validation with 422."
}

{
  "topic": "NOISE CONTROL",
  "_test_note": "Validates the mentions_penalty=true filter is actually applied and reflected in reasoning, scoped to the NOISE CONTROL topic."
}

{
  "query": "keep certain animals",
  "_test_note": "Validates the mentions_permit=true filter surfaces section 161.09 (Permits to keep certain animals), a real permit-requiring section."
}

{
  "topic": "NOISE CONTROL",
  "limit": 0,
  "_test_note": "TopicFilterRequest.limit is constrained to ge=1 per app/models.py; 0 must fail validation with 422."
}

{
  "query": "license",
  "limit": 51,
  "_test_note": "TopicFilterRequest.limit is constrained to le=50 per app/models.py; 51 must fail validation with 422."
}

{
  "urls": ["https://example.invalid/test.html"],
  "_test_note": "example.invalid is an RFC 2606 reserved test domain that will never resolve, so this can never cause a real outbound fetch. Validates /ingest now requires INGEST_API_KEY - a real security gap that was open before this test suite was written (see docs/DEPLOYMENT.md)."
}

{
  "urls": [],
  "_test_note": "IngestRequest.urls has min_length=1 per app/models.py; an empty list must fail validation with 422 (checked before the API-key gate would even matter for this shape)."
}

{
  "urls": ["https://www.nyc.gov/assets/doh/downloads/pdf/about/healthcode/health-code-article161.pdf"],
  "_test_note": "Re-ingesting an already-seen URL upserts the document and replaces its chunks - safe to re-run. Requires the real {{ingest_api_key}} collection variable to be set locally; otherwise expect 401, which this test tolerates."
}
